msg.statusCode = 200;
msg.headers = { "Content-Type": "application/json" };
msg.payload = { ok: true, accepted: true };
return msg;

const base = String(env.get("SUPPORT_API_BASE_URL") || "http://localhost:3000/api").replace(/\/+$/, "");
const token = String(env.get("SUPPORT_INTEGRATION_TOKEN") || "").trim();

const raw = (msg.payload && typeof msg.payload === "object") ? msg.payload : {};

function norm(value) {
  const text = String(value ?? "").trim();
  if (!text) return undefined;
  const lowered = text.toLowerCase();
  if (lowered === "null" || lowered === "undefined") return undefined;
  return text;
}

const externalUserId =
  norm(raw.externalUserId) ||
  norm(raw.userId) ||
  norm(raw.clientId) ||
  norm(raw.senderId) ||
  norm(raw.channelUserId);

const externalChatId =
  norm(raw.externalChatId) ||
  norm(raw.externalThreadId) ||
  norm(raw.chatId) ||
  norm(raw.threadId) ||
  norm(raw.dialogId);

const payload = {
  connector: "LK_ACADEMY_WEB_MESSENGER",
  externalUserId,
  externalChatId,
  displayName: norm(raw.displayName) || norm(raw.clientName) || norm(raw.senderName),
  username: norm(raw.username),
  phone: norm(raw.phone) || norm(raw.primaryPhone),
  email: norm(raw.email),
  stationId: norm(raw.stationId),
  stationName: norm(raw.stationName),
  selectedStationId: norm(raw.selectedStationId) || norm(raw.stationId),
  selectedStationName: norm(raw.selectedStationName) || norm(raw.stationName),
  subject: norm(raw.subject),
  text: norm(raw.text) || norm(raw.message) || norm(raw.content),
  eventType: norm(raw.eventType),
  direction: norm(raw.direction) || "INBOUND",
  kind: norm(raw.kind),
  meta: {
    source: "lk_academy",
    receivedAt: new Date().toISOString(),
    payload: raw
  }
};

if (!payload.externalUserId && !payload.externalChatId && !payload.phone && !payload.email) {
  node.warn("LK Academy payload without identifiers");
  return null;
}

msg.method = "POST";
msg.url = base + "/support/dialogs/events";
msg.headers = { "Content-Type": "application/json" };
if (token) {
  msg.headers["x-integration-token"] = token;
}
msg.payload = payload;
return msg;

const code = Number(msg.statusCode || 0);
if (code < 200 || code >= 300) {
  node.warn("LK Academy ingest failed: HTTP " + (code || "n/a") + "; body=" + (typeof msg.payload === "string" ? msg.payload : JSON.stringify(msg.payload)));
} else {
  node.log("LK Academy ingest OK: HTTP " + code);
}
return msg;
